const items = $input.all();
let domains = [];
let actions = [];

for (const item of items) {
  const d = item.json;
  if (d.data && Array.isArray(d.data) && d.data.length > 0) {
    const first = d.data[0];
    if (first.api_name !== undefined && first.action === undefined) {
      domains = d.data;
    } else if (first.action !== undefined) {
      actions = d.data;
    }
  }
}

const domainNames = [...new Set(domains.map(d => d.api_name))].sort();
const actionsByApi = {};
const actionCounts = {};
for (const a of actions) {
  const api = a.api_name || 'unknown';
  if (!actionsByApi[api]) actionsByApi[api] = [];
  actionsByApi[api].push(a.action);
  actionCounts[api] = (actionCounts[api] || 0) + 1;
}

const groups = {
  google: domainNames.filter(d => d.startsWith('google_') || ['ga4', 'gmail', 'youtube', 'google_ads', 'google_search_console', 'google_tag_manager', 'google_calendar', 'google_drive', 'google_my_business'].includes(d)),
  ai_providers: domainNames.filter(d => ['openai', 'anthropic', 'gemini', 'groq', 'deepseek', 'perplexity', 'ollama', 'bedrock', 'huggingface', 'mistral', 'openrouter', 'qwen'].includes(d)),
  ad_platforms: domainNames.filter(d => d.includes('ads') || ['semrush', 'twitter', 'linkedin', 'meta_ads', 'pinterest_ads', 'reddit_ads', 'x_ads'].includes(d)),
  crm_sales: domainNames.filter(d => ['hubspot', 'salesforce', 'apollo', 'gong'].includes(d)),
  productivity: domainNames.filter(d => ['slack', 'notion', 'outlook', 'onedrive', 'excel', 'teams'].includes(d)),
  creative: domainNames.filter(d => ['creatomate', 'gamma', 'leonardo'].includes(d)),
  dev_ops: domainNames.filter(d => ['github', 'vercel', 'wordpress'].includes(d)),
  browser: domainNames.filter(d => ['browser', 'browser_use', 'browserbase', 'e2b'].includes(d))
};

const registrySummary = Object.entries(actionCounts).sort((a,b) => b[1] - a[1]).slice(0, 30).map(([api, count]) => `${api}(${count})`).join(', ');

return [{ json: { domainNames, actionsByApi, actionCounts, groups, registrySummary, totalDomains: domainNames.length, totalActions: actions.length, scanDate: new Date().toISOString().split('T')[0] } }];

const registry = $input.first().json;
const groups = registry.groups;
const scanDate = registry.scanDate;
const actionCounts = registry.actionCounts;
const registrySummary = registry.registrySummary;
const queries = [];
const aiList = (groups.ai_providers || []).join(', ');
const aiActions = (groups.ai_providers || []).map(a => `${a}: ${actionCounts[a] || 0} actions`).join(', ');
queries.push({ phase: 'action_audit', category: 'AI / LLM Providers', query: `What new API endpoints, models, features, or capabilities were added by these AI providers in the last 7 days (as of ${scanDate}): ${aiList}? I currently have these action counts: ${aiActions}. Tell me SPECIFICALLY: any new API endpoints or methods added, new models released, new parameters/options on existing endpoints, pricing changes, and deprecations. Include version numbers, endpoint paths, and dates.` });
queries.push({ phase: 'action_audit', category: 'Google APIs', query: `Check the Google API changelogs for the last 7 days (as of ${scanDate}). APIs: Google Ads API, GA4 Data API, Search Console API, GTM API, Gmail API, Calendar API, Drive API, YouTube Data API, GMB API, Gemini API. List new endpoints, scopes, report types, version bumps, deprecation deadlines.` });
queries.push({ phase: 'action_audit', category: 'Advertising Platforms', query: `What API updates were released in the last 7 days (as of ${scanDate}) by: Meta Marketing API, LinkedIn Marketing API, Microsoft Advertising API, Amazon Ads API, Pinterest Ads API, Reddit Ads API, X Ads API? New versions, endpoints, targeting options, conversion tracking, deprecations.` });
queries.push({ phase: 'action_audit', category: 'CRM & Sales', query: `What new API endpoints or capabilities were added in the last 7 days (as of ${scanDate}) by: HubSpot API, Salesforce REST API, Apollo.io API, Gong API? New objects, endpoints, webhook events, rate limit changes, migration deadlines.` });
queries.push({ phase: 'action_audit', category: 'Productivity & Collaboration', query: `API updates in the last 7 days (as of ${scanDate}) by: Slack API, Notion API, Microsoft Graph API? New endpoints, scopes, webhook events, Block types, deprecations.` });
queries.push({ phase: 'new_api_radar', category: 'Big Tech New APIs & Services', query: `What brand NEW APIs, SDKs, or developer services were LAUNCHED (not updated) in the last 14 days (as of ${scanDate}) by Google, AWS, Apple, Microsoft, Salesforce, Adobe, Cloudflare? For each: what it does, REST API availability, pricing/free tier, relevance to B2B marketing automation.` });
queries.push({ phase: 'tool_discovery', category: 'New Free APIs & Tools', query: `Search Product Hunt (last 7 days), GitHub trending, Hacker News for NEW AI tools and APIs as of ${scanDate} relevant to: B2B marketing automation, cold email, content generation, SEO, lead enrichment, browser automation, workflow automation. Only tools with REST API or self-hostable. I already have: ${registrySummary}. Don't list tools I already have.` });
queries.push({ phase: 'tool_discovery', category: 'Research & Intelligence Tools', query: `New features or API capabilities in the last 14 days (as of ${scanDate}) by: Perplexity AI, Exa.ai, Tavily, SerpAPI, ScrapingBee, Browserless, Firecrawl, Apify, PhantomBuster, Clay? New endpoints, models, data sources, pricing changes.` });
queries.push({ phase: 'tool_discovery', category: 'SEO & Content Tools', query: `New features or API updates in the last 7 days (as of ${scanDate}) by: SEMrush, Ahrefs, Moz, Surfer SEO, Clearscope, Frase, Copy.ai, Jasper AI, WordPress REST API, Webflow API, Vercel? Also any notable NEW SEO or AI writing APIs.` });
return queries.map(q => ({ json: q }));

