const items = $input.all();
const registry = $node['Process Registry Data'].json;
const results = { action_audit: [], new_api_radar: [], tool_discovery: [] };
const queryOrder = [{phase:'action_audit',category:'AI / LLM Providers'},{phase:'action_audit',category:'Google APIs'},{phase:'action_audit',category:'Advertising Platforms'},{phase:'action_audit',category:'CRM & Sales'},{phase:'action_audit',category:'Productivity & Collaboration'},{phase:'new_api_radar',category:'Big Tech New APIs & Services'},{phase:'tool_discovery',category:'New Free APIs & Tools'},{phase:'tool_discovery',category:'Research & Intelligence Tools'},{phase:'tool_discovery',category:'SEO & Content Tools'}];
const unhelpful = /I cannot provide|I don't have|I would need|I apologize/i;
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const meta = queryOrder[i] || {phase:'action_audit',category:'Unknown'};
  let content = '', citations = [];
  if (item.json.choices && item.json.choices[0]) { content = item.json.choices[0].message?.content || ''; citations = item.json.citations || []; }
  else if (item.json.error) { content = '_Error: ' + (item.json.error.message||'API error') + '_'; }
  const skipped = unhelpful.test(content) || content.length < 50;
  results[meta.phase].push({ phase:meta.phase, category:meta.category, content: skipped?'_No actionable intel this week_':content, citations, hasUpdates:!skipped&&content.length>100, skipped });
}
return [{ json: { results, scanDate:registry.scanDate, totalDomains:registry.totalDomains, totalActions:registry.totalActions } }];

const data = $input.first().json;
const results = data.results;
const scanDate = data.scanDate || new Date().toISOString().split('T')[0];
const totalDomains = data.totalDomains || 51;
const totalActions = data.totalActions || 401;
function toSlack(t) { return t.replace(/\*\*(.+?)\*\*/g,'*$1*').replace(/\[([^\]]+)\]\(([^)]+)\)/g,'<$2|$1>').replace(/\[\d+\]/g,'').trim(); }
function fmtBullets(content, cites) { let lines = toSlack(content).split('\n').map(l=>l.trim()).filter(l=>l&&!l.toLowerCase().includes('no significant update')); lines = lines.map(l => l.startsWith('- ')||l.startsWith('\u2022 ') ? l : '- '+l); if (cites && cites.length > 0) lines.push('_Sources: '+cites.slice(0,3).map((c,i)=>`<${c}|src ${i+1}>`).join(' | ')+'_'); return lines.join('\n'); }
const phaseH = { action_audit:':mag: Action Gaps \u2014 New Endpoints on APIs We Use', new_api_radar:':rocket: New API Launches from Big Tech', tool_discovery:':star2: New Tools & APIs Worth Evaluating' };
const catE = { 'AI / LLM Providers':':robot_face:','Google APIs':':mag:','Advertising Platforms':':chart_with_upwards_trend:','CRM & Sales':':handshake:','Productivity & Collaboration':':gear:','Big Tech New APIs & Services':':rocket:','New Free APIs & Tools':':star2:','Research & Intelligence Tools':':microscope:','SEO & Content Tools':':pencil2:' };
const blocks = [];
blocks.push({ type:'header', text:{type:'plain_text',text:'API & Tool Intelligence Brief',emoji:true} });
blocks.push({ type:'context', elements:[{type:'mrkdwn',text:`:calendar: Week of ${scanDate}  |  *${totalDomains} APIs monitored*  |  *${totalActions} actions tracked*`}] });
blocks.push({ type:'divider' });
let totalFindings = 0;
for (const phase of ['action_audit','new_api_radar','tool_discovery']) {
  const secs = results[phase]||[];
  const active = secs.filter(s=>s.hasUpdates&&!s.skipped);
  const quiet = secs.filter(s=>!s.hasUpdates||s.skipped);
  totalFindings += active.length;
  blocks.push({ type:'section', text:{type:'mrkdwn',text:phaseH[phase]} });
  if (!active.length) { blocks.push({ type:'context', elements:[{type:'mrkdwn',text:'_No actionable findings this week_'}] }); }
  else { for (const s of active) { let fmt = fmtBullets(s.content, s.citations); if (fmt.length>2800) fmt = fmt.substring(0,2800)+'\n_...truncated_'; blocks.push({ type:'section', text:{type:'mrkdwn',text:`${catE[s.category]||':pushpin:'} *${s.category}*\n${fmt}`} }); } }
  if (quiet.length) blocks.push({ type:'context', elements:[{type:'mrkdwn',text:`:white_check_mark: *No changes:* ${quiet.map(s=>s.category).join(', ')}`}] });
  blocks.push({ type:'divider' });
}
blocks.push({ type:'context', elements:[{type:'mrkdwn',text:`_Ascend GTM Intelligence  |  ${totalFindings} categories with updates  |  Perplexity sonar-pro  |  Mondays 9 AM ET_`}] });
const fallback = `API & Tool Intelligence Brief \u2014 Week of ${scanDate}: ${totalFindings} categories with findings across ${totalDomains} APIs.`;
return [{ json: { blocks:blocks.slice(0,49), text:fallback, totalFindings } }];
